args.sparql:
SELECT ?albumLabel ?designerLabel WHERE { 
  ?band wdt:P31 wd:Q215380 ; 
        wdt:P1196 wd:Q65 ;
        wdt:P175 ?album .
  ?album wdt:P31 wd:Q5561 ;
         wdt:P981 wd:Q679366 ;
         wdt:P2534 ?designer .
  ?designer rdfs:label ?designerLabel .
  ?album rdfs:label ?albumLabel .
  FILTER(LANG(?designerLabel) = 'en')
  FILTER(LANG(?albumLabel) = 'en')
}
